  1→import React from 'react';
  2→import { useNavigate, useSearchParams } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useInfiniteQuery } from '@tanstack/react-query';
  5→import { getStories } from '../../../../API/StoryApi';
  6→import { motion } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryBrowser.css';
  9→
 10→const STATUS_LABELS = { ongoing: 'Ongoing', completed: 'Completed', hiatus: 'Hiatus' };
 11→const STATUS_FILTERS = [
 12→    { value: null, label: 'All' },
 13→    { value: 'ongoing', label: 'Ongoing' },
 14→    { value: 'completed', label: 'Completed' },
 15→    { value: 'hiatus', label: 'Hiatus' },
 16→];
 17→
 18→const StoryCard = ({ story, onClick }) => {
 19→    const author = story.users;
 20→    return (
 21→        <motion.div
 22→            className="story-card"
 23→            initial={{ opacity: 0, y: 10 }}
 24→            animate={{ opacity: 1, y: 0 }}
 25→            whileHover={{ y: -3 }}
 26→            onClick={onClick}
 27→        >
 28→            <div className="story-card-cover">
 29→                {story.cover_url ? (
 30→                    <img src={story.cover_url} alt={story.title} loading="lazy" />
 31→                ) : (
 32→                    <div className="story-card-cover-placeholder">
 33→                        <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="var(--text-muted)">
 34→                            <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
 35→                        </svg>
 36→                    </div>
 37→                )}
 38→            </div>
 39→            <div className="story-card-info">
 40→                <h3 className="story-card-title">{story.title}</h3>
 41→                {author && (
 42→                    <div className="story-card-author">
 43→                        {author.image_url && <img src={author.image_url} alt="" className="story-card-author-avatar" />}
 44→                        <span>{author.name}</span>
 45→                    </div>
 46→                )}
 47→                <div className="story-card-meta">
 48→                    <span className={`story-status-badge story-status-${story.status}`}>
 49→                        {STATUS_LABELS[story.status] || story.status}
 50→                    </span>
 51→                    <span className="story-card-stats">
 52→                        {(story.vote_count || 0)} votes &middot; {(story.read_count || 0)} reads
 53→                    </span>
 54→                </div>
 55→                {story.tags && story.tags.length > 0 && (
 56→                    <div className="story-card-tags">
 57→                        {story.tags.slice(0, 3).map(tag => (
 58→                            <span key={tag} className="story-card-tag">{tag}</span>
 59→                        ))}
 60→                    </div>
 61→                )}
 62→            </div>
 63→        </motion.div>
 64→    );
 65→};
 66→
 67→const StoryBrowser = () => {
 68→    const navigate = useNavigate();
 69→    const { session } = useAuth();
 70→    const token = session?.access_token;
 71→    const [searchParams, setSearchParams] = useSearchParams();
 72→    const statusFilter = searchParams.get('status') || null;
 73→
 74→    const {
 75→        data,
 76→        isLoading,
 77→        hasNextPage,
 78→        fetchNextPage,
 79→        isFetchingNextPage,
 80→    } = useInfiniteQuery({
 81→        queryKey: ['storiesBrowse', statusFilter],
 82→        queryFn: ({ pageParam = null }) => getStories(12, pageParam, statusFilter, null, token),
 83→        getNextPageParam: (lastPage) => {
 84→            if (!lastPage?.hasMore || !lastPage.data?.length) return undefined;
 85→            return lastPage.data[lastPage.data.length - 1].created_at;
 86→        },
 87→        initialPageParam: null,
 88→        refetchOnWindowFocus: false,
 89→    });
 90→
 91→    const stories = data?.pages?.flatMap(p => p.data) || [];
 92→
 93→    return (
 94→        <div className="story-browser">
 95→            <div className="story-browser-header">
 96→                <h2 className="story-browser-title">Stories</h2>
 97→                {session && (
 98→                    <div className="story-browser-header-actions">
 99→                        <button
100→                            className="story-browser-my-btn"
101→                            onClick={() => navigate('/home/stories/library')}
102→                        >
103→                            My Library
104→                        </button>
105→                        <button
106→                            className="story-browser-my-btn"
107→                            onClick={() => navigate('/home/stories/dashboard')}
108→                        >
109→                            My Stories
110→                        </button>
111→                        <button
112→                            className="story-browser-new-btn"
113→                            onClick={() => navigate('/home/stories/new')}
114→                        >
115→                            + Write
116→                        </button>
117→                    </div>
118→                )}
119→            </div>
120→
121→            <div className="story-browser-filters">
122→                {STATUS_FILTERS.map(f => (
123→                    <button
124→                        key={f.label}
125→                        className={`story-filter-btn ${statusFilter === f.value ? 'story-filter-btn-active' : ''}`}
126→                        onClick={() => {
127→                            if (f.value) {
128→                                setSearchParams({ status: f.value });
129→                            } else {
130→                                setSearchParams({});
131→                            }
132→                        }}
133→                    >
134→                        {f.label}
135→                    </button>
136→                ))}
137→            </div>
138→
139→            {isLoading ? (
140→                <div className="story-browser-loading">
141→                    <BeatLoader size={10} color="var(--text-muted)" />
142→                </div>
143→            ) : stories.length === 0 ? (
144→                <div className="story-browser-empty">
145→                    <p>No stories found.</p>
146→                </div>
147→            ) : (
148→                <>
149→                    <div className="story-browser-grid">
150→                        {stories.map(story => (
151→                            <StoryCard
152→                                key={story.id}
153→                                story={story}
154→                                onClick={() => navigate(`/home/stories/${story.id}`)}
155→                            />
156→                        ))}
157→                    </div>
158→                    {hasNextPage && (
159→                        <div className="story-browser-load-more">
160→                            <button
161→                                className="story-browser-load-more-btn"
162→                                onClick={() => fetchNextPage()}
163→                                disabled={isFetchingNextPage}
164→                            >
165→                                {isFetchingNextPage ? (
166→                                    <BeatLoader size={8} color="var(--text-secondary)" />
167→                                ) : (
168→                                    'Load more'
169→                                )}
170→                            </button>
171→                        </div>
172→                    )}
173→                </>
174→            )}
175→        </div>
176→    );
177→};
178→
179→export default StoryBrowser;
