  1→.story-browser {
  2→    width: 100%;
  3→    max-width: 750px;
  4→    box-sizing: border-box;
  5→    margin: 0 auto;
  6→    padding: 20px 16px;
  7→    font-family: var(--font-ui);
  8→}
  9→
 10→.story-browser-header {
 11→    display: flex;
 12→    align-items: center;
 13→    justify-content: space-between;
 14→    margin-bottom: 16px;
 15→}
 16→
 17→.story-browser-title {
 18→    font-size: 1.4rem;
 19→    font-weight: 600;
 20→    color: var(--text-primary);
 21→    margin: 0;
 22→}
 23→
 24→.story-browser-header-actions {
 25→    display: flex;
 26→    gap: 8px;
 27→}
 28→
 29→.story-browser-my-btn {
 30→    padding: 7px 14px;
 31→    border: 1px solid var(--border-light);
 32→    border-radius: 8px;
 33→    background: none;
 34→    color: var(--text-secondary);
 35→    font-size: 0.82rem;
 36→    cursor: pointer;
 37→    transition: background-color 0.12s ease;
 38→}
 39→
 40→.story-browser-my-btn:hover {
 41→    background: var(--bg-hover);
 42→}
 43→
 44→.story-browser-new-btn {
 45→    padding: 7px 16px;
 46→    border: none;
 47→    border-radius: 8px;
 48→    background: var(--accent-dark);
 49→    color: var(--bg-primary);
 50→    font-size: 0.82rem;
 51→    font-weight: 500;
 52→    cursor: pointer;
 53→    transition: opacity 0.15s ease;
 54→}
 55→
 56→.story-browser-new-btn:hover {
 57→    opacity: 0.85;
 58→}
 59→
 60→.story-browser-filters {
 61→    display: flex;
 62→    gap: 8px;
 63→    margin-bottom: 20px;
 64→    flex-wrap: wrap;
 65→}
 66→
 67→.story-filter-btn {
 68→    padding: 6px 14px;
 69→    border: 1px solid var(--border-light);
 70→    border-radius: 20px;
 71→    background: none;
 72→    color: var(--text-secondary);
 73→    font-size: 0.8rem;
 74→    cursor: pointer;
 75→    transition: all 0.12s ease;
 76→}
 77→
 78→.story-filter-btn:hover {
 79→    background: var(--bg-hover);
 80→}
 81→
 82→.story-filter-btn-active {
 83→    background: var(--accent-dark);
 84→    color: var(--bg-primary);
 85→    border-color: var(--accent-dark);
 86→}
 87→
 88→.story-filter-btn-active:hover {
 89→    background: var(--accent-dark);
 90→    opacity: 0.85;
 91→}
 92→
 93→.story-browser-loading {
 94→    display: flex;
 95→    justify-content: center;
 96→    padding: 60px 0;
 97→}
 98→
 99→.story-browser-empty {
100→    text-align: center;
101→    padding: 60px 20px;
102→    color: var(--text-secondary);
103→    font-size: 0.95rem;
104→}
105→
106→.story-browser-grid {
107→    display: grid;
108→    grid-template-columns: repeat(3, 1fr);
109→    gap: 16px;
110→}
111→
112→.story-card {
113→    background: var(--bg-card);
114→    border: 1px solid var(--border-card);
115→    border-radius: 12px;
116→    overflow: hidden;
117→    cursor: pointer;
118→    transition: box-shadow 0.15s ease;
119→}
120→
121→.story-card:hover {
122→    box-shadow: var(--shadow-card);
123→}
124→
125→.story-card-cover {
126→    width: 100%;
127→    aspect-ratio: 3 / 4;
128→    overflow: hidden;
129→    background: var(--bg-secondary);
130→}
131→
132→.story-card-cover img {
133→    width: 100%;
134→    height: 100%;
135→    object-fit: cover;
136→}
137→
138→.story-card-cover-placeholder {
139→    width: 100%;
140→    height: 100%;
141→    display: flex;
142→    align-items: center;
143→    justify-content: center;
144→}
145→
146→.story-card-info {
147→    padding: 10px 12px 12px;
148→}
149→
150→.story-card-title {
151→    font-size: 0.88rem;
152→    font-weight: 600;
153→    color: var(--text-primary);
154→    margin: 0 0 6px 0;
155→    display: -webkit-box;
156→    -webkit-line-clamp: 2;
157→    -webkit-box-orient: vertical;
158→    overflow: hidden;
159→    line-height: 1.3;
160→}
161→
162→.story-card-author {
163→    display: flex;
164→    align-items: center;
165→    gap: 6px;
166→    font-size: 0.75rem;
167→    color: var(--text-secondary);
168→    margin-bottom: 8px;
169→}
170→
171→.story-card-author-avatar {
172→    width: 18px;
173→    height: 18px;
174→    border-radius: 50%;
175→    object-fit: cover;
176→}
177→
178→.story-card-meta {
179→    display: flex;
180→    align-items: center;
181→    gap: 8px;
182→    margin-bottom: 6px;
183→    flex-wrap: wrap;
184→}
185→
186→.story-card-stats {
187→    font-size: 0.7rem;
188→    color: var(--text-muted);
189→}
190→
191→.story-card-tags {
192→    display: flex;
193→    gap: 4px;
194→    flex-wrap: wrap;
195→}
196→
197→.story-card-tag {
198→    padding: 2px 7px;
199→    border-radius: 10px;
200→    background: var(--bg-hover);
201→    font-size: 0.65rem;
202→    color: var(--text-secondary);
203→}
204→
205→.story-browser-load-more {
206→    display: flex;
207→    justify-content: center;
208→    padding: 24px 0;
209→}
210→
211→.story-browser-load-more-btn {
212→    padding: 10px 28px;
213→    border: 1px solid var(--border-light);
214→    border-radius: 8px;
215→    background: none;
216→    color: var(--text-secondary);
217→    font-size: 0.85rem;
218→    cursor: pointer;
219→    transition: background-color 0.12s ease;
220→    min-width: 120px;
221→    display: flex;
222→    align-items: center;
223→    justify-content: center;
224→}
225→
226→.story-browser-load-more-btn:hover:not(:disabled) {
227→    background: var(--bg-hover);
228→}
229→
230→@media (max-width: 768px) {
231→    .story-browser-grid {
232→        grid-template-columns: repeat(2, 1fr);
233→    }
234→}
235→
236→@media (max-width: 480px) {
237→    .story-browser {
238→        padding: 16px 12px;
239→    }
240→
241→    .story-browser-grid {
242→        grid-template-columns: repeat(2, 1fr);
243→        gap: 10px;
244→    }
245→
246→    .story-card-info {
247→        padding: 8px 10px 10px;
248→    }
249→
250→    .story-card-title {
251→        font-size: 0.82rem;
252→    }
253→}
